protected string TabsClassnames =>
    new CssBuilder("mud-tabs")
        .AddClass($"mud-tabs-rounded", ApplyEffectsToContainer && Rounded)
        .AddClass($"mud-paper-outlined", ApplyEffectsToContainer && Outlined)

