            divs = comp.FindAll("div.mud-tabs-tabbar-wrapper div.mud-tab");
            // all tabs should show
            divs.Count.Should().Be(4);
            divs[0].InnerHtml.Should().Be("One");
            divs[1].InnerHtml.Should().Be("Two");
            divs[2].InnerHtml.Should().Be("Three");
